function searchFilm(){let e=document,t=e.getElementById("id_film").value;try{e.getElementById("yohoho").remove(),playVideo(t,e)}catch{playVideo(t,e)}}function playVideo(e,t){let o=t.createElement("div");o.id="yohoho",o.setAttribute("data-kinopoisk",e),t.getElementById("content").append(o);const n=t.createElement("script");n.src="//yohoho.cc/yo.js",t.getElementById("content").append(n)}document.addEventListener("keyup",(e=>{"Enter"===e.code&&searchFilm()}));